import { v4 as uuid } from "uuid"
import SocialItem from "./Item"

const SocialBar = () => {

    const data = [
        {icon:'github',     url:'https://github.com/subhibhat'},
        {icon:'facebook',   url:'https://fb.com/subhibhat'},
        {icon:'instagram',  url:'https://instagram.com/subhibhat'},
        {icon:'steam',      url:'https://steamcommunity.com/id/subhibhat/'}
    ]

    return (
        <ul className="m-0 p-0 social">
            {data.map(item => {
                return <SocialItem key={uuid()} icon={item.icon} url={item.url} />
            })}
        </ul>
    )
}

export default SocialBar