import { useEffect, useState } from "react"
import parse from "rss-to-json"

const BlogFeed = () => {
    
    const [blogs, setBlogs] = useState({})

    const getMediumBlog = async () => {
        const blogs = await parse('https://medium.com/feed/@subhibhat')
        console.log(JSON.stringify(blogs, null, 3))
    }

    useEffect(() => {
        getMediumBlog()
        return () => setBlogs({})
    },[])

    return (
        <ul>
            {/* {blogs.map(item => {
                return <li></li>
            })} */}
        </ul>
    )
}

export default BlogFeed